package com.Java_Practice;

public class EvenAndOdd {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		for (int i = 1; i <= 100; i++) {
			if (i % 2 == 0)
				System.out.println(i + " Is Even");
			else
				System.out.println(i + " Is Odd");

		}

	}

}
